def {{nama_fungsi}}(y_true, y_pred, labels=None):
    """Build confusion matrix from true and predicted labels.
    Returns dict: {'matrix': 2D list, 'labels': list, 'size': int}
    matrix[i][j] = count where true=i, pred=j
    """
    if labels is None:
        labels = sorted(set(y_true) | set(y_pred))
    label_idx = {label: i for i, label in enumerate(labels)}
    n = len(labels)
    matrix = [[0] * n for _ in range(n)]
    for t, p in zip(y_true, y_pred):
        if t in label_idx and p in label_idx:
            matrix[label_idx[t]][label_idx[p]] += 1
    return {'matrix': matrix, 'labels': labels, 'size': n}


def {{nama_fungsi_print}}(cm_result):
    """Pretty-print confusion matrix."""
    matrix = cm_result['matrix']
    labels = cm_result['labels']
    max_label = max(len(str(l)) for l in labels) if labels else 3
    max_val = max(max(row) for row in matrix) if matrix else 0
    cell_width = max(max_label + 1, len(str(max_val)) + 2)
    header = ' ' * (max_label + 2) + ''.join(str(l).rjust(cell_width) for l in labels)
    print('Predicted →')
    print(header)
    print('Actual ↓')
    for i, label in enumerate(labels):
        row_str = str(label).ljust(max_label + 2) + ''.join(str(matrix[i][j]).rjust(cell_width) for j in range(len(labels)))
        print(row_str)

def {{nama_fungsi}}(y_true, y_pred, labels=None, digits=4):
    """Generate classification report with precision, recall, F1 per class.
    Returns dict with per-class metrics and averages.
    """
    if labels is None:
        labels = sorted(set(y_true) | set(y_pred))
    report = {}
    total = len(y_true)
    for label in labels:
        tp = sum(1 for t, p in zip(y_true, y_pred) if t == label and p == label)
        fp = sum(1 for t, p in zip(y_true, y_pred) if t != label and p == label)
        fn = sum(1 for t, p in zip(y_true, y_pred) if t == label and p != label)
        precision = tp / (tp + fp) if (tp + fp) > 0 else 0.0
        recall = tp / (tp + fn) if (tp + fn) > 0 else 0.0
        f1 = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0.0
        support = sum(1 for t in y_true if t == label)
        report[label] = {
            'precision': round(precision, digits),
            'recall': round(recall, digits),
            'f1': round(f1, digits),
            'support': support,
        }
    # Macro average
    n_classes = len(labels)
    report['_macro_avg'] = {
        'precision': round(sum(r['precision'] for r in report.values() if isinstance(r, dict) and 'precision' in r) / n_classes, digits),
        'recall': round(sum(r['recall'] for r in report.values() if isinstance(r, dict) and 'recall' in r) / n_classes, digits),
        'f1': round(sum(r['f1'] for r in report.values() if isinstance(r, dict) and 'f1' in r) / n_classes, digits),
        'support': total,
    }
    # Weighted average
    if total > 0:
        report['_weighted_avg'] = {
            'precision': round(sum(r['precision'] * r['support'] for r in report.values() if isinstance(r, dict) and 'precision' in r) / total, digits),
            'recall': round(sum(r['recall'] * r['support'] for r in report.values() if isinstance(r, dict) and 'recall' in r) / total, digits),
            'f1': round(sum(r['f1'] * r['support'] for r in report.values() if isinstance(r, dict) and 'f1' in r) / total, digits),
            'support': total,
        }
    report['_accuracy'] = sum(1 for t, p in zip(y_true, y_pred) if t == p) / total if total > 0 else 0.0
    return report

class {{nama_class}}:
    """One-hot encoder for categorical data.
    encoder = OneHotEncoder()
    encoder.fit(['cat', 'dog', 'bird'])
    encoder.transform(['cat', 'bird']) → [[1,0,0], [0,0,1]]
    """
    def __init__(self):
        self.classes_ = []
        self._class_to_idx = {}

    def fit(self, categories):
        """Learn categories from data."""
        self.classes_ = sorted(set(categories))
        self._class_to_idx = {c: i for i, c in enumerate(self.classes_)}
        return self

    def transform(self, data):
        """Transform categories to one-hot vectors."""
        result = []
        for item in data:
            vec = [0] * len(self.classes_)
            if item in self._class_to_idx:
                vec[self._class_to_idx[item]] = 1
            result.append(vec)
        return result

    def fit_transform(self, data):
        """Fit and transform in one step."""
        self.fit(data)
        return self.transform(data)

    def inverse_transform(self, vectors):
        """Convert one-hot vectors back to categories."""
        result = []
        for vec in vectors:
            idx = vec.index(1) if 1 in vec else -1
            if 0 <= idx < len(self.classes_):
                result.append(self.classes_[idx])
            else:
                result.append(None)
        return result

    @property
    def n_classes(self):
        return len(self.classes_)

class {{nama_class}}:
    """K-Fold cross-validation splitter.
    for train_idx, test_idx in KFold(k=5).split(data):
        X_train = [data[i] for i in train_idx]
        X_test = [data[i] for i in test_idx]
    """
    def __init__(self, k={{default_k}}, shuffle=False, seed=None):
        self.k = k
        self.shuffle = shuffle
        self.seed = seed

    def split(self, data):
        """Yield (train_indices, test_indices) for each fold."""
        n = len(data)
        indices = list(range(n))
        if self.shuffle:
            import random
            rng = random.Random(self.seed)
            rng.shuffle(indices)
        fold_size = n // self.k
        for i in range(self.k):
            start = i * fold_size
            end = start + fold_size if i < self.k - 1 else n
            test_idx = indices[start:end]
            train_idx = indices[:start] + indices[end:]
            yield train_idx, test_idx

    def get_n_splits(self):
        return self.k


class StratifiedKFold:
    """Stratified K-Fold: preserves class distribution in each fold."""
    def __init__(self, k=5, shuffle=False, seed=None):
        self.kfold = KFold(k=k, shuffle=shuffle, seed=seed)
        self.k = k

    def split(self, X, y):
        """Yield (train_indices, test_indices) stratified by y."""
        from collections import defaultdict
        groups = defaultdict(list)
        for i, label in enumerate(y):
            groups[label].append(i)
        label_folds = {}
        for label, idxs in groups.items():
            kf = self.kfold
            kf.k = self.k
            label_folds[label] = list(kf.split(idxs))
        for fold_i in range(self.k):
            train_idx, test_idx = [], []
            for label in groups:
                folds = label_folds[label]
                t_idx, te_idx = folds[fold_i]
                train_idx.extend([groups[label][j] for j in t_idx])
                test_idx.extend([groups[label][j] for j in te_idx])
            yield train_idx, test_idx

    def get_n_splits(self):
        return self.k

class {{nama_class_std}}:
    """Standard scaler: z-score normalization. x' = (x - mean) / std
    scaler = StandardScaler()
    scaler.fit([[1,2],[3,4],[5,6]])
    scaled = scaler.transform([[2,3]])
    """
    def __init__(self):
        self.mean_ = None
        self.std_ = None

    def fit(self, data):
        """Compute mean and std per feature column."""
        if not data:
            return self
        n_features = len(data[0])
        self.mean_ = [0.0] * n_features
        self.std_ = [0.0] * n_features
        n = len(data)
        for row in data:
            for j in range(n_features):
                self.mean_[j] += row[j]
        self.mean_ = [m / n for m in self.mean_]
        for row in data:
            for j in range(n_features):
                self.std_[j] += (row[j] - self.mean_[j]) ** 2
        self.std_ = [(s / n) ** 0.5 for s in self.std_]
        self.std_ = [s if s > 1e-10 else 1.0 for s in self.std_]
        return self

    def transform(self, data):
        return [[(x - self.mean_[j]) / self.std_[j] for j, x in enumerate(row)] for row in data]

    def fit_transform(self, data):
        self.fit(data)
        return self.transform(data)

    def inverse_transform(self, data):
        return [[x * self.std_[j] + self.mean_[j] for j, x in enumerate(row)] for row in data]


class {{nama_class_minmax}}:
    """Min-Max scaler: scale to [0, 1]. x' = (x - min) / (max - min)"""
    def __init__(self, feature_range=(0, 1)):
        self.min_ = None
        self.max_ = None
        self.range = feature_range

    def fit(self, data):
        if not data:
            return self
        n_features = len(data[0])
        self.min_ = [min(row[j] for row in data) for j in range(n_features)]
        self.max_ = [max(row[j] for row in data) for j in range(n_features)]
        return self

    def transform(self, data):
        lo, hi = self.range
        result = []
        for row in data:
            scaled = []
            for j, x in enumerate(row):
                rng = self.max_[j] - self.min_[j]
                if rng < 1e-10:
                    scaled.append(lo)
                else:
                    scaled.append(lo + (x - self.min_[j]) / rng * (hi - lo))
            result.append(scaled)
        return result

    def fit_transform(self, data):
        self.fit(data)
        return self.transform(data)

def {{nama_fungsi_roc}}(y_true, y_scores):
    """Compute ROC curve points (FPR, TPR) at various thresholds.
    y_true: binary labels (0/1).
    y_scores: predicted scores/probabilities.
    Returns dict with 'fpr', 'tpr', 'thresholds' lists.
    """
    pairs = sorted(zip(y_scores, y_true), reverse=True)
    total_pos = sum(1 for _, y in pairs if y == 1)
    total_neg = sum(1 for _, y in pairs if y == 0)
    if total_pos == 0 or total_neg == 0:
        return {'fpr': [0, 1], 'tpr': [0, 1], 'thresholds': []}
    fpr_list, tpr_list, thresholds = [0.0], [0.0], []
    tp, fp = 0, 0
    for score, label in pairs:
        if label == 1:
            tp += 1
        else:
            fp += 1
        tpr_list.append(tp / total_pos)
        fpr_list.append(fp / total_neg)
        thresholds.append(score)
    return {'fpr': fpr_list, 'tpr': tpr_list, 'thresholds': thresholds}


def {{nama_fungsi}}(y_true, y_scores):
    """Compute AUC-ROC using trapezoidal rule.
    Returns float between 0 and 1.
    """
    roc = {{nama_fungsi_roc}}(y_true, y_scores)
    fpr = roc['fpr']
    tpr = roc['tpr']
    auc = 0.0
    for i in range(1, len(fpr)):
        auc += (fpr[i] - fpr[i-1]) * (tpr[i] + tpr[i-1]) / 2.0
    return round(auc, 6)
